COPY public.grammar_patterns (id, pattern, category, jlpt_level, formation_rules, examples, common_mistakes, related_patterns, created_at) FROM stdin;
1	〜てもいいです	Permission	N5	[{"rule": "Te-form of verb", "step": 1}, {"rule": "Add もいいです", "step": 2}]	[{"en": "May I take photos?", "jp": "写真を撮ってもいいですか。", "romaji": "Shashin wo totte mo ii desu ka."}, {"en": "You may enter.", "jp": "入ってもいいです。", "romaji": "Haitte mo ii desu."}]	[{"mistake": "Using dictionary form instead of te-form", "explanation": "Must use te-form: 食べてもいい not 食べもいい"}]	\N	2026-03-10 18:47:25.815647
2	〜てはいけません	Prohibition	N5	[{"rule": "Te-form of verb", "step": 1}, {"rule": "Add はいけません", "step": 2}]	[{"en": "You must not smoke here.", "jp": "ここで吸ってはいけません。", "romaji": "Koko de sutte wa ikemasen."}, {"en": "Do not touch.", "jp": "触ってはいけません。", "romaji": "Sawatte wa ikemasen."}]	[{"mistake": "Forgetting は particle", "explanation": "Must include は: てはいけません not ていけません"}]	\N	2026-03-10 18:47:25.815647
3	〜たいです	Desire	N5	[{"rule": "Stem form (masu-form without masu)", "step": 1}, {"rule": "Add たいです", "step": 2}]	[{"en": "I want to eat sushi.", "jp": "寿司を食べたいです。", "romaji": "Sushi wo tabetai desu."}, {"en": "I want to go to Japan.", "jp": "日本に行きたいです。", "romaji": "Nihon ni ikitai desu."}]	[{"mistake": "Using te-form instead of stem form", "explanation": "Use stem form: 食べたい not 食べてたい"}]	\N	2026-03-10 18:47:25.815647
4	〜ことができます	Ability	N5	[{"rule": "Dictionary form of verb", "step": 1}, {"rule": "Add ことができます", "step": 2}]	[{"en": "I can speak Japanese.", "jp": "日本語が話せることができます。", "romaji": "Nihongo wo hanasu koto ga dekimasu."}, {"en": "I can swim.", "jp": "泳ぐことができます。", "romaji": "Oyogu koto ga dekimasu."}]	[{"mistake": "Using potential form before ことが", "explanation": "Use dictionary form: 話すことができます not 話せることができます"}]	\N	2026-03-10 18:47:25.815647
5	〜なければなりません	Obligation	N5	[{"rule": "Negative form (nai) without ない", "step": 1}, {"rule": "Add なければなりません", "step": 2}]	[{"en": "I must study.", "jp": "勉強しなければなりません。", "romaji": "Benkyou shinakereba narimasen."}, {"en": "I have to go early.", "jp": "早く行かなければなりません。", "romaji": "Hayaku ikanakereba narimasen."}]	[{"mistake": "Using te-form", "explanation": "Must use nai-stem: しなければ not してなければ"}]	\N	2026-03-10 18:47:25.815647
