25	は (topic marker)	Particles	N5	[{"rule": "Place after topic", "step": 1}, {"rule": "Replaces が or を for contrast/emphasis", "step": 2}]	[{"en": "I am a student (as for me).", "jp": "私は学生です。", "romaji": "Watashi wa gakusei desu."}, {"en": "Today (unlike other days) I am busy.", "jp": "今日は忙しいです。", "romaji": "Kyou wa isogashii desu."}]	[{"mistake": "Using は for existence sentences", "explanation": "Use が for あります/います: 本があります not 本はあります for simple existence"}]	\N	2026-03-11 12:11:25.307012
26	が (subject marker)	Particles	N5	[{"rule": "Marks grammatical subject", "step": 1}, {"rule": "Used with あります/います, 好き/嫌い, ability", "step": 2}]	[{"en": "There is a cat. / A cat exists.", "jp": "猫がいます。", "romaji": "Neko ga imasu."}, {"en": "I will do it (emphasis: I, not others).", "jp": "私がやります。", "romaji": "Watashi ga yarimasu."}]	[{"mistake": "Confusing は and が", "explanation": "は marks topic (old info), が marks subject (new info). 私は is neutral, 私が emphasizes me"}]	\N	2026-03-11 12:11:25.307012
27	を (object marker)	Particles	N5	[{"rule": "Place after direct object", "step": 1}, {"rule": "Marks what the verb acts upon", "step": 2}]	[{"en": "I eat sushi.", "jp": "寿司を食べます。", "romaji": "Sushi wo tabemasu."}, {"en": "I read a book.", "jp": "本を読みます。", "romaji": "Hon wo yomimasu."}]	[{"mistake": "Using を with intransitive verbs", "explanation": "Intransitive verbs like 行く use に/へ, not を: 学校に行く not 学校を行く"}]	\N	2026-03-11 12:11:25.307012
